#include<bits/stdc++.h>
using namespace std;
struct node{
	char name[35];
	int english,math,chinese,total;
}d[100001];
bool qwq(node a,node b) {
    if (abs(a.chinese-b.chinese)<=5&&abs(a.math-b.math)<=5&&abs(a.english-b.english)<=5&&abs(a.total-b.total)<=10)
        return 1;
    else return 0;
}
int main()
{
	int n,i,j,sum=0;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%s",d[i].name);
		scanf("%d%d%d",&d[i].chinese,&d[i].math,&d[i].english);
		d[i].total=d[i].chinese+d[i].math+d[i].english;
	}
	for (int i=1;i<=n;i++)
	{
    	for (int j=i+1;j<=n;j++)
		{
    	    if (qwq(d[i],d[j]))
    	    {
   	     		printf("%s %s\n",d[i].name,d[j].name);
			}
    	}
	}
	return 0;
}
